/* PointHistoryEntity */
INSERT 
INTO tb_mbm_point_history (
						  point_id		, dr_cr		, cr_point_type		, dr_point_type
						, admin_gift_yn
						, amount
						, avil_amount

						, memo
						, create_date
						, create_id
)VALUES(	
		 #{pointId}
		,#{drCr}
		,#{crPointType}
		,#{drPointType}

		,#{adminGiftYn}
		,#{amount}
		,#{amount}

		,#{memo}
		,NOW()
		,#{createId}
);

/* PointHistoryDetailEntity */
INSERT 
INTO tb_mbm_point_history_detail (
						  history_id
						,dr_point_type

						, tot_amt
						, act_amt
						, rem_amt

						, npay_id
						, cash_id

						, create_date
						, create_id
)VALUES(	
		 #{historyId}
		,#{drPointType}
		,#{totAmt}
		,#{actAmt}
		,#{remAmt}

		,#{npayId}
		,#{cashId}

		,NOW()
		,#{createId}
);

INSERT INTO tb_mbm_point_history (
	point_id, dr_cr, cr_point_type, dr_point_type, admin_gift_yn
	,amount
	,avil_amount
	, memo, create_date, create_id
)
SELECT 
	#{pointId}, #{drCr}, #{crPointType}, #{drPointType},#{adminGiftYn}
	, #{amount}
	, #{amount}
	, #{memo}, NOW(), #{createId}
FROM DUAL
WHERE NOT EXISTS (
	SELECT 1 FROM tb_mbm_point_history 
	WHERE point_id = #{pointId} AND cr_point_type = 'REV'
);
